import{_ as i,c as e,o as l,a as s}from"./app.64ab3a52.js";const _=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[{"level":2,"title":"rem, 计算出375的屏幕，1rem,单位出现小数怎么处理","slug":"rem-计算出375的屏幕-1rem-单位出现小数怎么处理","link":"#rem-计算出375的屏幕-1rem-单位出现小数怎么处理","children":[]},{"level":2,"title":"rem和vw的使用场景","slug":"rem和vw的使用场景","link":"#rem和vw的使用场景","children":[]},{"level":2,"title":"Display 的常见属性","slug":"display-的常见属性","link":"#display-的常见属性","children":[]},{"level":2,"title":"css的link标签和@import的区别","slug":"css的link标签和-import的区别","link":"#css的link标签和-import的区别","children":[]},{"level":2,"title":"display:none、visibility:hidden、opacity:0的区别","slug":"display-none、visibility-hidden、opacity-0的区别","link":"#display-none、visibility-hidden、opacity-0的区别","children":[]},{"level":2,"title":"scss样式穿透原因及原生原理","slug":"scss样式穿透原因及原生原理","link":"#scss样式穿透原因及原生原理","children":[]}],"relativePath":"interview/面试-CSS.md"}'),a={name:"interview/面试-CSS.md"},t=s('<p><a href="https://segmentfault.com/a/1190000013325778" target="_blank" rel="noreferrer">50道CSS基础面试题（附答案）</a></p><h2 id="rem-计算出375的屏幕-1rem-单位出现小数怎么处理" tabindex="-1">rem, 计算出375的屏幕，1rem,单位出现小数怎么处理 <a class="header-anchor" href="#rem-计算出375的屏幕-1rem-单位出现小数怎么处理" aria-hidden="true">#</a></h2><h2 id="rem和vw的使用场景" tabindex="-1">rem和vw的使用场景 <a class="header-anchor" href="#rem和vw的使用场景" aria-hidden="true">#</a></h2><h2 id="display-的常见属性" tabindex="-1">Display 的常见属性 <a class="header-anchor" href="#display-的常见属性" aria-hidden="true">#</a></h2><h2 id="css的link标签和-import的区别" tabindex="-1">css的link标签和@import的区别 <a class="header-anchor" href="#css的link标签和-import的区别" aria-hidden="true">#</a></h2><ol><li>概念</li></ol><ul><li>link标签属于HTML的标签，不仅仅可以加载样式还可以定义一些属性ref</li><li>@import属于CSS的语法，只能加载外部样式</li></ul><ol start="2"><li>加载顺序</li></ol><ul><li>link标签，加载页面时同时加载样式</li><li>@import，页面加载完成，才开始加载外部样式(如果把主页面样式写成@import会导致页面加载出来有一段时间样式缺失)</li></ul><ol start="3"><li>DOM操作区别</li></ol><ul><li>link是个标签，可以通过js新增删除样式</li><li>@import是css语法，无法通过js操作</li></ul><p>总结：</p><ul><li>性质不同，link是xhtml标签，无兼容性问题，可用于加载CSS文件的同时还可以进行RSS信息聚合等事务，而@import属于CSS范畴，在CSS2时提出，低版本浏览器不支持，只能用于加载CSS文件</li><li>加载时间不同，link引用CSS随页面载入时同时加载，@import需要在页面加载完毕后被需要时才会加载</li><li>写法不同，link是写在head标签中，而@import在html中只能写在style标签中</li><li>样式权重不同，link引用的样式权重高于@import</li></ul><h2 id="display-none、visibility-hidden、opacity-0的区别" tabindex="-1">display:none、visibility:hidden、opacity:0的区别 <a class="header-anchor" href="#display-none、visibility-hidden、opacity-0的区别" aria-hidden="true">#</a></h2><ul><li>opacity通过透明度隐藏dom，还有占位和可以点击（依然要渲染，消耗性能）</li><li>visibility控制可视性隐藏dom，还有占位和不可点击（不渲染，保留空间，消耗一丢丢性能）</li><li>display盒模型彻底隐藏（不渲染，不保留空间）</li></ul><p>性能： 浏览器GUI渲染线程、浏览器JS引擎线程 css渲染过程：布局(排列、重排、回流)-&gt;绘制(重绘)</p><p>开关<code>opacity</code>和开关<code>visibility</code>都会触发重绘</p><h2 id="scss样式穿透原因及原生原理" tabindex="-1">scss样式穿透原因及原生原理 <a class="header-anchor" href="#scss样式穿透原因及原生原理" aria-hidden="true">#</a></h2><p>内部写样式不生效，改为全局样式后生效的原因 在vue中用了scope组件样式，去改第三方组件之类的样式不生效的原因是第三方组件的样式是全局的，内部组件scope不会给第三方组件加data码，这样组件选择器会选不中它 scss提供给组件父级下的选择器加deep，让这部分样式编译成全局样式，不带data码</p><p>如果是原生css会不会遇到样式穿透的问题，如何解决</p>',20),r=[t];function n(d,o,c,p,h,m){return l(),e("div",null,r)}const u=i(a,[["render",n]]);export{_ as __pageData,u as default};
